+    instance.nmTokens.remove(nodeAddr);
+  }
+  
+  /**
+   * It will remove all the nm tokens from its cache
+   */
+  public static synchronized void clearCache() {
+    instance.nmTokens.clear();
+  }
{code}

Is this meant to be public for users? It should probably just return a java unmodifiable map wrapped around the internal and mention in the java doc that it returns an unmodifiable map. Unless its really required to create a snapshot of the token cache at that point in time.
